diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..1ad150d7523b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2253,7 +2253,6 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
       return BinaryOperator::CreateAdd(X, USub);
     }
   }
-
   // sub Op0, smin((sub nsw Op0, Z), 0) --> smax Op0, Z
   // sub Op0, smax((sub nsw Op0, Z), 0) --> smin Op0, Z
   if (MinMax->isSigned() && match(Y, m_ZeroInt()) &&
@@ -2263,6 +2262,40 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // sub(smin(X + C, Y), smin(X, Y)) --> select(X < Y, C, 0)
+  // sub(umin(X + C, Y), umin(X, Y)) --> select(X < Y, C, 0)
+  // This works because:
+  // - If X < Y: smin/umin(X + C, Y) = X + C, smin/umin(X, Y) = X, result = C
+  // - If X >= Y: smin/umin(X + C, Y) = Y, smin/umin(X, Y) = Y, result = 0
+  // Requires C > 0 and the add to have no-signed-wrap (for smin) or
+  // no-unsigned-wrap (for umin).
+  Value *X2, *Y2;
+  const APInt *C;
+  if (MinMax->getIntrinsicID() == Intrinsic::smin &&
+      match(Op0, m_SMin(m_NSWAddLike(m_Value(X2), m_APInt(C)),
+                        m_Value(Y2))) &&
+      MinMax->getLHS() == X2 && MinMax->getRHS() == Y2 &&
+      MinMax->hasOneUse()) {
+    // Check that C is positive (1 in the common case)
+    if (C->isStrictlyPositive()) {
+      Value *Cmp = Builder.CreateICmpSLT(X2, Y2);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, *C),
+                                ConstantInt::get(Ty, 0));
+    }
+  }
+  if (MinMax->getIntrinsicID() == Intrinsic::umin &&
+      match(Op0, m_UMin(m_NUWAddLike(m_Value(X2), m_APInt(C)),
+                        m_Value(Y2))) &&
+      MinMax->getLHS() == X2 && MinMax->getRHS() == Y2 &&
+      MinMax->hasOneUse()) {
+    // Check that C is positive (1 in the common case)
+    if (C->isStrictlyPositive()) {
+      Value *Cmp = Builder.CreateICmpULT(X2, Y2);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, *C),
+                                ConstantInt::get(Ty, 0));
+    }
+  }
+
   return nullptr;
 }

